    private void processDocument(ImportJob job) {
        try {
            job.setStatus("PROCESSING");
            Document document = job.getDocument();
            Element root = document.getDocumentElement();
            
            NodeList records = root.getElementsByTagName("record");
            job.setTotalRecords(records.getLength());
            
            for (int i = 0; i < records.getLength(); i++) {
                Element record = (Element) records.item(i);
                processRecord(record);
                job.incrementProcessedRecords();
            }
            
            job.setStatus("COMPLETED");
            job.setMessage("Successfully processed " + job.getProcessedRecords() + " records");
        } catch (Exception e) {
            job.setStatus("FAILED");
            job.setMessage("Error: " + e.getMessage());
        }
    }
    
    private void processBulkDocument(ImportJob job) {
        try {
            job.setStatus("PROCESSING");
            Document document = job.getDocument();
            Element root = document.getDocumentElement();
            
            NodeList entities = root.getElementsByTagName("entity");
            job.setTotalRecords(entities.getLength());
            
            List<Future<Boolean>> futures = new ArrayList<>();
            
            for (int i = 0; i < entities.getLength(); i++) {
                final Element entity = (Element) entities.item(i);
                Future<Boolean> future = executorService.submit(() -> {
                    try {
                        processBulkEntity(entity);
                        return true;
                    } catch (Exception e) {
                        return false;
                    }
                });
                futures.add(future);
            }
            
            int processed = 0;
            for (Future<Boolean> future : futures) {
                try {
                    if (future.get()) {
                        processed++;
                        job.incrementProcessedRecords();
                    }
                } catch (Exception e) {
                    // Continue processing
                }
            }
            
            job.setStatus("COMPLETED");
            job.setMessage("Successfully processed " + processed + " entities");
        } catch (Exception e) {
            job.setStatus("FAILED");
            job.setMessage("Error: " + e.getMessage());
        }
    }
    
